import { createSlice } from "@reduxjs/toolkit";

const initialState = localStorage.getItem("cart")
  ? JSON.parse(localStorage.getItem("cart"))
  : { cartItems: [] }; // Fixed typo here

const addDecimal = (num) => {
  return (Math.round(num * 100) / 100).toFixed(2); // Fixed rounding
};

const CartSlice = createSlice({
  name: "cart",
  initialState,
  reducers: {
    addToCart: (state, action) => {
      const items = action.payload;
      const existitem = state.cartItems.find((x) => x._id === items._id); // Fixed missing return

      if (existitem) {
        state.cartItems = state.cartItems.map((x) =>
          x._id === existitem._id ? items : x
        ); // Fixed map on cartItems
      } else {
        state.cartItems = [...state.cartItems, items];
      }

      // Calculate item price
      state.itemsprice = addDecimal(
        state.cartItems.reduce((acc, item) => acc + item.price * item.qty, 0)
      ); // Fixed cartItems typo and added initial value for reduce

      // Calculate shipping price
      state.shippingprice = addDecimal(state.itemsprice > 100 ? 0 : 10);

      // Calculate the tax price
      state.taxprice = addDecimal(Number((0.18 * state.itemsprice).toFixed(2)));

      // Calculate the total price
      state.totalprice = (
        Number(state.itemsprice) +
        Number(state.shippingprice) +
        Number(state.taxprice)
      ).toFixed(2);

      localStorage.setItem("cart", JSON.stringify(state)); // Fixed JSON.stringify
    },
  },
});

export const { addToCart } = CartSlice.actions;
export default CartSlice.reducer;
